import { Component, input } from '@angular/core';
import { Image } from '../image/image';

@Component({
  selector: 'vn-app-logo',
  imports: [Image],
  template: `<vn-image [src]="src()" [alt]="alt()" />`,
  standalone: true,
  host: {
    class: 'h-full p-2',
    '[class]': "''",
  },
})
export class AppLogo {
  /** Image source url */
  src = input('favicon.ico');

  /** Image description */
  alt = input('App Logo');
}

import { Component, computed, input } from '@angular/core';

@Component({
  selector: 'vn-box',
  standalone: true,
  template: `
    <div
      class="flex flex-col"
      [style.height]="computedHeight()"
      [style.width]="computedWidth()"
      [title]="title()"
      [style.aspectRatio]="computedRatio()"
    >
      <ng-content>
        <p> No Content</p>
      </ng-content>
    </div>
  `,
})
export class Box {
  size = input(0);

  heightRatio = input(1);
  widthRatio = input(1);

  computedWidth = computed(() => {
    return this.size() * this.widthRatio() + this.unit();
  });

  computedHeight = computed(() => {
    return this.size() * this.heightRatio() + this.unit();
  });

  computedRatio = computed(() => {
    return this.heightRatio() + '/' + this.widthRatio();
  });

  unit = input('px');

  title = computed(() => {
    return this.computedWidth() + ' X ' + this.computedHeight();
  });
}

import { Component } from '@angular/core';

/**
 * Flexbox column container
 */
@Component({
  selector: 'vn-flex-col',
  template: `<ng-content></ng-content>`,
  host: {
    class:
      'flex flex-col grow h-full w-full overflow-hidden overflow-y-auto',
  },
})
export class FlexCol { }

import { Component, computed, input, signal } from '@angular/core';

/**
 * Flexbox row container
 */
@Component({
  selector: 'vn-flex-row',
  template: `<ng-content ></ng-content>`,
  host: {
    "[class]": "hostClasses()"
  },
})
export class FlexRow {
  justifyEnd = input(false)
  flexGap = input(false)
  baseClasses = signal('flex flex-row grow w-full overflow-hidden h-full items-center');
  hostClasses = computed(() => {
    return `${this.baseClasses()} ${this.justifyEnd() ? "justify-end" : ""} ${this.flexGap() ? "gap-2" : ""}`
  })

}

import { Component, input } from '@angular/core';

@Component({
  selector: 'vn-image',
  template: `<img
    [src]="src()"
    [alt]="alt()"
    class="h-auto max-h-full w-auto max-w-full "
    [style.width]="width() + 'px'"
    [style.height]="height() + 'px'"
  />`,
  standalone: true,
  host: {
    class: 'h-full',
  },
})
export class Image {
  width = input<number>();
  height = input<number>();
  src = input('favicon.ico');
  alt = input('');
}

