const _inputCommonModules = [
    CommonModule,
    FormsModule,
    ReactiveFormsModule,
    MatFormFieldModule,
    MatInputModule,
    MatIconModule,
    MatButtonModule,
]

@NgModule({
    imports: [_inputCommonModules],
    exports: [_inputCommonModules]
})
export class InputCommonModule { }

@Component({
    imports: _inputCommonModules,
    selector: "vn-input-common",
    template: '<span>Abstract component</span>'
})
export class InputCommon {
    type = input<string>('text')
    label = input()
    hint = input()
    prefixText = input();
    prefixIcon = input();
    suffixText = input();
    suffixIcon = input();
    required = input(false)
    value = model<string>('')
    errors = input<string[]>()
}

