import { Component } from '@angular/core';
import { outputFromObservable, toObservable } from '@angular/core/rxjs-interop';
import { debounceTime, distinctUntilChanged } from 'rxjs';
import { InputCommon } from '../input-common/input-common';
import { InputCommonModule } from '../input-common/input-common.module';


@Component({
  selector: 'vn-input-text',
  imports: [
    InputCommonModule
  ],
  template: `

    @let __errors = errors();
    @let __prefixText =prefixText();
    @let __suffixText =suffixText();
    @let __prefixIcon =prefixIcon();
    @let __suffixIcon =suffixIcon();

    <mat-form-field >  
      <mat-label>{{label()}} </mat-label>
      <input #inputRef matInput [type]="type()"  [required]="required()" [(ngModel)]="value">


     @if(__prefixIcon) {  <mat-icon matIconPrefix>{{__prefixIcon}}</mat-icon>}
     @if(__suffixIcon) {  <mat-icon matIconSuffix>{{__suffixIcon}}</mat-icon>}

      @if(__prefixText){  <span matTextPrefix>{{__prefixText}}</span>}
      @if(__suffixText){  <span matTextSuffix>{{__suffixText}}</span>}



      @if(!inputRef.validity.valid){ 
        @if(__errors){ 
          @for(error of __errors; track error){ 
            <mat-error>{{error}}</mat-error>
          }
        }
      }
      <!--  -->
      @if(hint()){ 
        <mat-hint>{{hint()}}</mat-hint>
      }
      </mat-form-field>
  `,
  host: {
    class: "w-full"
  }
})
export class InputText extends InputCommon {



  onValueChange = outputFromObservable(toObservable(this.value).pipe(
    debounceTime(300),
    distinctUntilChanged()
  ))



}

